mapper.select:
SELECT a.*, b.name AS dept_name, c.name AS inst_name FROM sys_user_admin a LEFT JOIN sys_inst c ON a.inst_id = c.inst_id AND c.newlevel=0 LEFT JOIN sys_deptS b ON a.dept_id = b.dept_id AND b.newlevel=0
JOIN ( SELECT d.* FROM sys_dept d WHERE d.dept_id=#{deptId} OR d.parent_id=#{deptId} ) dd ON a.dept_id=dd.dept_id
WHERE 1=1 AND a.is_deleted=0 AND a.user_id != #{userId}
AND a.code LIKE CONCAT(CONCAT(#{user.code},'%'))
AND a.name LIKE CONCAT(CONCAT(#{user.name},'%'))
AND a.dept_id = #{user.deptId}
AND a.inst_id = #{user.instId}
AND a.state = #{user.state}
ORDER BY a.create_time DESC
